import sys

def drop_cap(s):
    if not isinstance(s, str):
        return ''  # Guard against non-str inputs (fixes potential index errors on None/list/etc.)
    result = []
    i = 0
    n = len(s)
    while i < n:
        if s[i].isspace():  # Handles space, tab, etc. (correction for general whitespace)
            result.append(s[i])  # Preserve exact WS char (space/tab/etc.)
            i += 1
        else:
            start = i
            while i < n and not s[i].isspace():  # Skip non-WS (correction)
                i += 1
            end = i
            word_len = end - start
            if word_len <= 2:
                result.append(s[start:end])  # Unchanged
            else:
                first = s[start].upper()
                rest = s[start + 1:end].lower()
                result.append(first + rest)
    return ''.join(result)

