def get_neighbors(c: str) -> set[str]:
    if c == 'a':
        return {'b'}
    if c == 'z':
        return {'y'}
    o = ord(c)
    return {chr(o - 1), chr(o + 1)}

def solve(st: str) -> bool:
    n = len(st)
    if n == 0:
        return True
    for i in range(n // 2):
        left = get_neighbors(st[i])
        right = get_neighbors(st[n - 1 - i])
        if not (left & right):  # Empty intersection → impossible for this pair
            return False
    return True

