def is_substitution_possible(s1, s2):
    if len(s1) != len(s2) or not s1:  # Added explicit check for empty strings (len=0)
        return False
    mapping = {}
    used = set()
    for i in range(len(s1)):
        p = s1[i]
        c = s2[i]
        if p in mapping:
            if mapping[p] != c:
                return False
        else:
            if c in used:
                return False
            mapping[p] = c
            used.add(c)
    return True

