def factorize(n):
    # Parse/validate n to positive int ni >=1 exactly (handles str/int/float, decimals like "100.0")
    if isinstance(n, int):
        ni = n
    elif isinstance(n, float):
        if not n.is_integer() or n <= 0:
            return None
        ni = int(n)
    elif isinstance(n, str):
        s = n.strip()
        if not s:
            return None
        parts = s.split('.')
        if len(parts) == 1:
            try:
                ni = int(parts[0])
            except ValueError:
                return None
        elif len(parts) == 2:
            integer_part = parts[0]
            decimal_part = parts[1].lstrip('0')
            if decimal_part != '':
                return None  # non-zero decimal
            try:
                ni = int(integer_part)
            except ValueError:
                return None
        else:
            return None
    else:
        return None  # other types (list, dict, etc.)

    if ni <= 0 or ni != 1 and ni < 2:
        return None
    if ni == 1:
        return {'factors': [1], 'primes': [1], 'exponents': [1]}

    # Factorize ni >=2 (matches plan)
    factors = []
    primes = []
    exponents = []
    # 2s
    count = 0
    while ni % 2 == 0:
        count += 1
        factors.append(2)
        ni //= 2
    if count > 0:
        primes.append(2)
        exponents.append(count)
    # Odds
    i = 3
    while i * i <= ni:
        count = 0
        while ni % i == 0:
            count += 1
            factors.append(i)
            ni //= i
        if count > 0:
            primes.append(i)
            exponents.append(count)
        i += 2
    # Remainder
    if ni > 1:
        factors.append(ni)
        primes.append(ni)
        exponents.append(1)
    return {'factors': factors, 'primes': primes, 'exponents': exponents}

def getAllPrimeFactors(n):
    f = factorize(n)
    return f['factors'] if f else []

def getUniquePrimeFactorsWithCount(n):
    f = factorize(n)
    return [f['primes'], f['exponents']] if f else [[], []]

def getUniquePrimeFactorsWithProducts(n):
    f = factorize(n)
    if not f:
        return []
    potencies = []
    for i in range(len(f['primes'])):
        p = f['primes'][i]
        e = f['exponents'][i]
        potency = 1  # Matches plan: loop mult (exact bigint)
        for _ in range(e):
            potency *= p
        potencies.append(potency)
    return potencies

