def find_max_diff_couple(arr):
    if not arr or not hasattr(arr, '__len__') or len(arr) == 0:
        return False  # Correction: False (bool) per plan, not None
    if len(arr) == 1:
        # Correction: Match plan Step 1 exactly for len=1
        s = arr[0]
        if not isinstance(s, str):
            return False
        parts = s.split('-')
        if len(parts) != 2:
            return False
        try:
            a = int(parts[0].strip())
            b = int(parts[1].strip())
            diff = abs(a - b)
            return s if diff > 0 else False  # Correction: False (bool) per plan
        except ValueError:
            return False
    # General case (len >1)
    max_diff = -1
    result = None
    for s in arr:
        if not isinstance(s, str):
            continue
        parts = s.split('-')
        if len(parts) != 2:
            continue
        try:
            a = int(parts[0].strip())
            b = int(parts[1].strip())
            diff = abs(a - b)
            if diff > max_diff:
