a_ord = ord('a')
vowels = set('aeiou')
forbidden = set('code')

def transform(c):
    orig = c
    pos = ord(c) - a_ord
    if c in {'c', 'o'}:
        shift = -1
    elif c == 'd':
        shift = -3
    elif c == 'e':
        shift = -4
    elif c in vowels:
        shift = -5
    else:
