def process_sentence(sentence: str) -> str:
    tokens = sentence.split()
    processed_tokens = []
    PUNCT_CHARS = '.,!?;:'
    for token in tokens:
        punct = ''
        core = token
        if token and token[-1] in PUNCT_CHARS:
            punct = token[-1]
            core = token[:-1]
        len_core = len(core)
        t_count = sum(1 for c in core if c.lower() == 't')
        if len_core > 6 or t_count >= 2:
            new_core = core[::-1]
        elif len_core == 1:
            new_core = '0'
        elif len_core == 2 or punct == ',':
            new_core = core.upper()
        else:
            new_core = core
        new_token = new_core + punct
        processed_tokens.append(new_token)
    return ' '.join(processed_tokens)

