import sys

def isqrt(n):
    if n == 0 or n == 1:
        return n
    left, right = 1, n // 2 + 1
    ans = 0
    while left <= right:
        mid = left + (right - left) // 2
        if mid <= n // mid:
            ans = mid
            left = mid + 1
        else:
            right = mid - 1
    return ans

def is_madhav_array(a):
    L = len(a)
    if L < 3:
        return False
    disc = 1 + 8 * L
    sqrt_disc = isqrt(disc)
    if sqrt_disc * sqrt_disc != disc:
        return False
    n = (sqrt_disc - 1) // 2
    if n * (n + 1) // 2 != L or n < 2:
        return False
    S = a[0]
    idx = 1
    for k in range(2, n + 1):
        group_sum = 0
        for _ in range(k):
            if idx >= L:
                return False
            group_sum += a[idx]
            idx += 1
        if group_sum != S:
            return False
    return idx == L

