import re

def solution(sequence):
    # Check if already strictly increasing
    already_good = True
    for k in range(1, len(sequence)):
        if sequence[k] <= sequence[k - 1]:
            already_good = False
            break
    if already_good:
        return True

    n = len(sequence)
    # Try removing each index i (modified: combined checks with early exits)
    for i in range(n):
        # Prefix check [0:i]
        prefix_ok = True
        for j in range(1, i):
            if sequence[j] <= sequence[j - 1]:
                prefix_ok = False
                break
        if not prefix_ok:
            continue

        # Suffix check [i+1:n]
        suffix_ok = True
        for j in range(i + 2, n):
            if sequence[j] <= sequence[j - 1]:
                suffix_ok = False
                break
        if not suffix_ok:
            continue

        # Bridge check
        bridge_ok = True
        if i > 0 and i < n - 1:
            if sequence[i + 1] <= sequence[i - 1]:
                bridge_ok = False
        if prefix_ok and suffix_ok and bridge_ok:
            return True
    return False

