def calc_tip(p: int, r: int) -> int:
    div = p // 10
    rem = p % 10
    rounded = (div + 1) * 10 if rem >= 5 else div * 10
    base_t = rounded // 10
    if r == 1:
        tip = base_t + 1
    elif r == 0:
        tip = base_t - 1
    else:  # r == -1
        tip = (base_t // 2) - 1
    return max(0, tip)

