def find_age_range(ages: list[int]) -> tuple[int | None, int | None, int | None]:
    if not ages:
        return (None, None, None)
    min_age = max_age = ages[0]
    for age in ages[1:]:
        if age < min_age:
            min_age = age
        if age > max_age:
            max_age = age
    return (min_age, max_age, max_age - min_age)

