import sys

# Integer square root via binary search (precise for large n/perfect squares, avoids float precision issues).
def isqrt(n):
    if n < 2:
        return n
    left, right = 1, n // 2
    while left <= right:
        mid = left + (right - left) // 2
        if mid * mid <= n:
            left = mid + 1
        else:
            right = mid - 1
    return right  # floor(sqrt(n))

def factors(n):
    # Input validation with conversion (handles str/float/valid numerics per plan).
    try:
        n = int(n)
    except (ValueError, TypeError):
        return -1
    if n < 1:
        return -1
    # Empty list for factors.
    factor_list = []
    # Safe isqrt for large n.
    sqrt_n = isqrt(n)
    # O(√n) loop: find pairs, skip duplicate for squares.
    for i in range(1, sqrt_n + 1):
        if n % i == 0:
            factor_list.append(i)
            if i != n // i:
                factor_list.append(n // i)
    # Sort descending (largest first, no dups).
    factor_list.sort(reverse=True)
    return factor_list

