def mix(s1, s2):
    count1 = [0] * 26
    count2 = [0] * 26
    # Correction 1: Do NOT use .lower(); only count existing lowercase a-z, ignore uppercase/non-letters.
    for char in s1:
        if 'a' <= char <= 'z':
            count1[ord(char) - ord('a')] += 1
    for char in s2:
        if 'a' <= char <= 'z':
            count2[ord(char) - ord('a')] += 1
    parts = []
    for i in range(26):
        letter = chr(ord('a') + i)
        maxc = max(count1[i], count2[i])
        if maxc <= 1:
            continue
        # Prefix logic unchanged (correct).
        if count1[i] == maxc == count2[i]:
            prefix = "=:"
        elif count1[i] == maxc:
            prefix = "1:"
        else:
            prefix = "2:"
        parts.append(prefix + letter * maxc)
    # Sorting key unchanged (handles desc length, asc lex perfectly).
    sorted_parts = sorted(parts, key=lambda p: (-len(p), p))
    # Correction 2: Explicit empty check (though '/'.join([]) == '', but safe).
    return '/'.join(sorted_parts) if sorted_parts else ""

