def solve(expression: str) -> int:
    s = expression
    qcount = s.count('?')
    if qcount == 0:
        return -1
    used_digits = set()
    for c in s:
        if c.isdigit():
            used_digits.add(int(c))
    candidates = [d for d in range(10) if d not in used_digits]

    pos_eq = s.find('=')
    if pos_eq == -1 or pos_eq == 0 or pos_eq == len(s) - 1:
        return -1
    left_str = s[:pos_eq]
    C_str = s[pos_eq + 1:]
    if not C_str:
        return -1

    i = 0
    if i < len(left_str) and left_str[i] == '-':
        i += 1
    while i < len(left_str) and (left_str[i].isdigit() or left_str[i] == '?'):
        i += 1
    if i == 0 or i == len(left_str):
        return -1
    A_str = left_str[:i]
    if i >= len(left_str):
        return -1
    op_char = left_str[i]
    if op_char not in '+-*':
        return -1
    B_str = left_str[i + 1:]
    if not B_str:
        return -1

    def replace_all(t: str, d: int) -> str:
        return t.replace('?', str(d))

    def valid_number(num_str: str) -> bool:
        if not num_str:
            return False
        neg = False
        start = 0
        if num_str[0] == '-':
            neg = True
            start = 1
        if start == len(num_str):
            return False
        digits_part = num_str[start:]
        if not digits_part or not all(c.isdigit() for c in digits_part):
            return False
        if digits_part[0] == '0' and len(digits_part) > 1:
            return False
        try:
            n = int(num_str)
            if n > 1000000 or n < -1000000:
                return False
            return True
        except ValueError:
            return False

    for d in candidates:
        A = replace_all(A_str, d)
        B = replace_all(B_str, d)
        C = replace_all(C_str, d)
        if not (valid_number(A) and valid_number(B) and valid_number(C)):
            continue
        na = int(A)
        nb = int(B)
        nc = int(C)
        if op_char == '+':
            left = na + nb
        elif op_char == '-':
            left = na - nb
        elif op_char == '*':
            left = na * nb
        else:
            continue
        if left == nc:
            return d
    return -1

