def preprocess(s: str) -> list[str]:
    # Per plan Step 2: handle hyphens, lowercase, split, filter 'and'/empties (fixes edge #3)
    words = s.replace('-', ' ').lower().split()
    return [w for w in words if w and w != 'and']

def parse(words: list[str], ones: dict, tens: dict, scales: dict) -> int:
    # Per plan Step 3: accumulators total/current, left-to-right logic (fixes all edges)
    total, current = 0, 0
    for word in words:
        if word.isdigit():
            # Correction: handle digit strings/ints (e.g., "1" → 1, passes failed tests)
            current += int(word)
        elif word in ones:
            current += ones[word]
        elif word in tens:
            current += tens[word]
        elif word in scales:
            val = scales[word]
            if word == 'hundred':
                current *= val
            else:  # thousand/million
                total += current * val
                current = 0
    total += current  # Final group
    return total

def word_to_int(s) -> int:
    # Correction: s = str(s) handles int inputs (no AttributeError)
    s = str(s)
    words = preprocess(s)
    return parse(words, ones, tens, scales)

