def is_perfect_square(x):
    if x < 0:
        return False
    if x == 0 or x == 1:
        return True
    left = 1
    right = x // 2 + 1
    while left <= right:
        mid = left + (right - left) // 2
        sq = mid * mid
        if sq == x:
            return True
        if sq < x:
            left = mid + 1
        else:
            right = mid - 1
    return False

def sum_of_squares(n):
    # Check 1 square.
    if is_perfect_square(n):
        return 1

    # Check 2 squares.
    a = 1
    while a * a <= n:
        rem = n - a * a
        if rem > 0 and is_perfect_square(rem):
            return 2
        a += 1

    # 3/4 squares via Legendre's theorem.
    num = n
    while num % 4 == 0:
        num //= 4
    if num % 8 == 7:
        return 4
    return 3

