def next_bigger(n: int) -> int:
    numStr = str(n)
    arr = list(numStr)
    n_len = len(arr)
    if n_len == 0:
        return -1
    k = -1
    for i in range(n_len - 2, -1, -1):
        if arr[i] < arr[i + 1]:
            k = i
            break
    if k == -1:
        return -1
    # Find rightmost l > k with arr[l] > arr[k]
    l = n_len - 1
    while l > k:
        if arr[l] > arr[k]:
            break
        l -= 1
    # Swap
    arr[k], arr[l] = arr[l], arr[k]
    # Reverse suffix (using two pointers)
    left, right = k + 1, n_len - 1
    while left < right:
        arr[left], arr[right] = arr[right], arr[left]
        left += 1
        right -= 1
    return int(''.join(arr))

