import sys

def sieve(maxa):
    spf = list(range(maxa + 1))
    for i in range(2, int(maxa ** 0.5) + 1):
        if spf[i] == i:
            for j in range(i * i, maxa + 1, i):
                if spf[j] == j:
                    spf[j] = i
    return spf

def factorize(x, spf):
    fac = []
    while x > 1:
        p = spf[x]
        e = 0
        while x % p == 0:
            x //= p
            e += 1
        fac.append((p, e))
    return fac

