def can(v, n, k, d):
    pos = 0
    r = 0
    covered = 0
    while pos + k - 1 < n:
        while r < n and v[r] <= v[pos] + d:
            r += 1
        max_end = r - 1
        if max_end < pos + k - 1:
            return False
        covered = max(covered, r)
        pos += k
    return covered >= n

def solve(n, k, vs):
    v = sorted(vs)
    low = 0
    high = 10**9 + 1
    while low < high:
        mid = (low + high) // 2
        if can(v, n, k, mid):
            high = mid
        else:
            low = mid + 1
    return low

