        left_down[k][y] = ptr if ptr <= n else n + 1

dp = [[0] * (m + 2) for _ in range(n + 2)]
prefix_vert = [[0] * (m + 2) for _ in range(n + 2)]

for i in range(1, n + 1):
    entry_ways = [0] * (m + 2)
    if i == 1:
        entry_ways[1] = 1
    else:
        for j in range(1, m + 1):
            l = left_down[i][j]
            if l <= i - 1:
                prev = prefix_vert[i - 1][j]
                prev_l = prefix_vert[l - 1][j] if l - 1 >= 0 else 0
                entry_ways[j] = (prev - prev_l + MOD) % MOD
    prefix_entry = [0] * (m + 2)
    for j in range(1, m + 1):
        prefix_entry[j] = (prefix_entry[j - 1] + entry_ways[j]) % MOD
    for j in range(1, m + 1):
        l = left_right[i][j]
        if l <= j:
            dp[i][j] = (prefix_entry[j] - prefix_entry[l - 1] + MOD) % MOD
        else:
            dp[i][j] = 0
    vert_entry = [0] * (m + 2)
    for j in range(1, m + 1):
        l = left_right[i][j]
        if i == 1 and j == 1:
            vert_entry[j] = 1
        elif l <= j - 1:
            pe_jm1 = prefix_entry[j - 1]
            pe_lm1 = prefix_entry[l - 1] if l - 1 >= 0 else 0
            vert_entry[j] = (pe_jm1 - pe_lm1 + MOD) % MOD
    for j in range(1, m + 1):
        prefix_vert[i][j] = (prefix_vert[i - 1][j] + vert_entry[j]) % MOD

