n, k = map(int, input().split())
a = list(map(int, input().split()))

prefix = [0] * (n + 1)
for i in range(1, n + 1):
    prefix[i] = prefix[i - 1] + a[i - 1]

S = prefix[n]
if S % k != 0:
    print("No")
else:
    target = S // k
    splits = []
    prev = 0
    cur_target = target
    for i in range(1, n + 1):
        if prefix[i] == cur_target:
            splits.append(i - prev)
            prev = i
            cur_target += target
    if len(splits) == k:
        print("Yes")
        print(' '.join(map(str, splits)))
    else:
        print("No")
